import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjFilePicker } from "./OjFilePicker";
export { OjFilePicker };

/**
 * Create an instance of [[OjFilePicker]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojFilePicker(driver, By.id('my-oj-file-picker'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojFilePicker(driver: DriverLike, by: By): Promise<OjFilePicker> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjFilePicker
  if (!(webEl instanceof OjFilePicker)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-file-picker>`);
  }
  return webEl;
}

register("oj-file-picker", OjFilePicker);
